import{_ as a,o as l,c as r,ag as e}from"./chunks/framework.CxZWPeXl.js";const c=JSON.parse('{"title":"階段管理","description":"","frontmatter":{},"headers":[],"relativePath":"zh-TW/admin-stages.md","filePath":"zh-TW/admin-stages.md"}'),i={name:"zh-TW/admin-stages.md"};function d(o,t,h,n,s,u){return l(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="階段管理" tabindex="-1">階段管理 <a class="header-anchor" href="#階段管理" aria-label="Permalink to &quot;階段管理&quot;">​</a></h1><blockquote><p>定義銷售練習的各個階段，設定 AI 評量的標準與目標</p></blockquote><h2 id="概覽" tabindex="-1">概覽 <a class="header-anchor" href="#概覽" aria-label="Permalink to &quot;概覽&quot;">​</a></h2><p>銷售階段是 AI Coach 練習流程的骨幹。每個階段代表銷售對話中的一個關鍵環節，AI 會根據階段定義來追蹤使用者的進展、判斷階段轉換、並產生對應的評量報告。</p><blockquote><p>此功能僅對具有階段管理權限的管理員開放。</p></blockquote><h2 id="進入方式" tabindex="-1">進入方式 <a class="header-anchor" href="#進入方式" aria-label="Permalink to &quot;進入方式&quot;">​</a></h2><ol><li>點擊頁面右上方的 <strong>管理設定圖示</strong>（齒輪）</li><li>在管理員後台中選擇「階段管理」</li></ol><hr><h2 id="頁面結構" tabindex="-1">頁面結構 <a class="header-anchor" href="#頁面結構" aria-label="Permalink to &quot;頁面結構&quot;">​</a></h2><p>頁面標題為「階段管理」，下方依階段編號排列顯示所有階段的卡片。</p><p>每張階段卡片包含：</p><table tabindex="0"><thead><tr><th>元素</th><th>說明</th></tr></thead><tbody><tr><td>標題</td><td>格式：「第 N 階段：{階段描述}」</td></tr><tr><td>客戶狀態描述</td><td>灰色文字，描述客戶在此階段的心理狀態或行為特徵</td></tr><tr><td>編輯按鈕</td><td>修改此階段的設定</td></tr><tr><td>刪除按鈕</td><td>刪除此階段（會彈出確認訊息）</td></tr></tbody></table><hr><h2 id="階段屬性說明" tabindex="-1">階段屬性說明 <a class="header-anchor" href="#階段屬性說明" aria-label="Permalink to &quot;階段屬性說明&quot;">​</a></h2><p>每個階段由以下三個屬性定義：</p><h3 id="階段編號" tabindex="-1">階段編號 <a class="header-anchor" href="#階段編號" aria-label="Permalink to &quot;階段編號&quot;">​</a></h3><ul><li>決定階段的先後順序</li><li>必須為正整數</li><li>不可與現有階段重複</li><li>建立後不可更改（提示：「階段編號不可更改」）</li></ul><h3 id="階段描述" tabindex="-1">階段描述 <a class="header-anchor" href="#階段描述" aria-label="Permalink to &quot;階段描述&quot;">​</a></h3><ul><li>此階段的名稱與目標說明</li><li>例如：「初次接觸客戶」、「深入探索需求」、「提出方案建議」</li></ul><h3 id="當前客戶狀態描述" tabindex="-1">當前客戶狀態描述 <a class="header-anchor" href="#當前客戶狀態描述" aria-label="Permalink to &quot;當前客戶狀態描述&quot;">​</a></h3><ul><li>描述客戶在此階段的狀態</li><li>AI 會參考此描述來模擬客戶的行為反應</li><li>例如：「客戶對業務員持觀望態度，尚未建立信任」</li></ul><hr><h2 id="新增階段" tabindex="-1">新增階段 <a class="header-anchor" href="#新增階段" aria-label="Permalink to &quot;新增階段&quot;">​</a></h2><ol><li>點擊頁面右上方的 <strong>「新增階段」</strong> 按鈕</li><li>在彈出的對話框中填寫：</li></ol><table tabindex="0"><thead><tr><th>欄位</th><th>類型</th><th>必填</th><th>說明</th></tr></thead><tbody><tr><td>階段編號</td><td>數字輸入</td><td>是</td><td>設定此階段的順序編號（正整數）</td></tr><tr><td>階段描述</td><td>文字輸入</td><td>是</td><td>描述此階段的名稱與目標</td></tr><tr><td>當前客戶狀態描述</td><td>文字輸入</td><td>是</td><td>描述客戶在此階段的狀態</td></tr></tbody></table><ol start="3"><li>點擊儲存完成新增</li></ol><hr><h2 id="編輯階段" tabindex="-1">編輯階段 <a class="header-anchor" href="#編輯階段" aria-label="Permalink to &quot;編輯階段&quot;">​</a></h2><ol><li>在對應的階段卡片上點擊 <strong>「編輯」</strong> 按鈕</li><li>在彈出的對話框中修改欄位（階段編號不可更改）</li><li>點擊儲存完成修改</li></ol><hr><h2 id="刪除階段" tabindex="-1">刪除階段 <a class="header-anchor" href="#刪除階段" aria-label="Permalink to &quot;刪除階段&quot;">​</a></h2><ol><li>在對應的階段卡片上點擊 <strong>「刪除」</strong> 按鈕</li><li>系統彈出確認對話框：「確定要刪除階段 &quot;XXX&quot; 嗎？」</li><li>確認後刪除</li></ol><blockquote><p>刪除階段可能影響進行中的練習與歷史評量的顯示，請謹慎操作。</p></blockquote><hr><h2 id="階段設計建議" tabindex="-1">階段設計建議 <a class="header-anchor" href="#階段設計建議" aria-label="Permalink to &quot;階段設計建議&quot;">​</a></h2><h3 id="設計原則" tabindex="-1">設計原則 <a class="header-anchor" href="#設計原則" aria-label="Permalink to &quot;設計原則&quot;">​</a></h3><ol><li><strong>循序漸進</strong> — 階段應由簡至難，符合實際銷售流程的自然推進</li><li><strong>目標明確</strong> — 每個階段應有清晰、可衡量的達成目標</li><li><strong>客戶導向</strong> — 客戶狀態描述應真實反映該階段客戶的心理狀態</li><li><strong>適量設計</strong> — 建議 3-7 個階段，過少缺乏挑戰性，過多則使練習冗長</li></ol><h3 id="常見階段範例" tabindex="-1">常見階段範例 <a class="header-anchor" href="#常見階段範例" aria-label="Permalink to &quot;常見階段範例&quot;">​</a></h3><table tabindex="0"><thead><tr><th>階段編號</th><th>階段描述</th><th>客戶狀態描述</th></tr></thead><tbody><tr><td>1</td><td>破冰建立信任</td><td>客戶對業務員持觀望態度，尚未建立信任感</td></tr><tr><td>2</td><td>需求探索</td><td>客戶開始放下戒心，但對自身保險需求認知模糊</td></tr><tr><td>3</td><td>方案說明</td><td>客戶已認同部分需求，開始關注具體方案內容</td></tr><tr><td>4</td><td>異議處理</td><td>客戶對方案有興趣但存在疑慮，需要進一步釐清</td></tr><tr><td>5</td><td>促成</td><td>客戶已大致認同方案，處於決策邊緣</td></tr></tbody></table><h3 id="階段與評量的關係" tabindex="-1">階段與評量的關係 <a class="header-anchor" href="#階段與評量的關係" aria-label="Permalink to &quot;階段與評量的關係&quot;">​</a></h3><p>階段定義直接影響 AI 的評量邏輯：</p><ol><li><strong>對話過程中</strong>：階段不會即時顯示或追蹤。使用者專注於與客戶互動即可</li><li><strong>對話結束後</strong>：AI 會回顧完整對話內容，根據您定義的階段標準，判定使用者最終達成了哪個階段</li><li><strong>評量報告</strong>： <ul><li>針對每個已達成的階段提供獨立評估</li><li>未達成所有階段時，分析「未晉升原因」</li><li>達成最後一個階段時，顯示「已達成所有階段」的祝賀訊息</li></ul></li><li><strong>練習歷史</strong>：每筆紀錄會記錄「達成階段」欄位，代表該次練習的最高達成階段編號</li></ol><p>因此，<strong>階段描述與客戶狀態描述的品質</strong>直接決定了 AI 評量的準確度。描述越清晰具體，AI 的判斷就越精準。</p><hr><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li>調整 <a href="./admin-prompts.html">Prompt 管理</a> 配合階段設定優化 AI 行為</li><li>維護 <a href="./admin-knowledge.html">知識庫</a> 提供各階段的參考知識</li><li>管理 <a href="./admin-users.html">使用者帳號</a> 設定使用權限</li></ul>',46)])])}const q=a(i,[["render",d]]);export{c as __pageData,q as default};
